import type { AreaDatapoint, BarDatapoint } from '../../../types/xy-chart.js';

type NumberOfCoordinatesByDimensionResult = {
  xCoordinateCount: 0 | 1 | 2;
  yCoordinateCount: 0 | 1 | 2;
};

export const numberOfCoordinatesByDimension = ({
  x1,
  x0,
  y1,
  y0,
}: BarDatapoint | AreaDatapoint): NumberOfCoordinatesByDimensionResult => ({
  xCoordinateCount: (Number(x0 !== undefined) + Number(x1 !== undefined)) as
    | 0
    | 1
    | 2,
  yCoordinateCount: (Number(y0 !== undefined) + Number(y1 !== undefined)) as
    | 0
    | 1
    | 2,
});
